  5→//! Notch command - JJ-aware commit with heat/pace context prefix
  6→//!
  7→//! This module handles the jjx_notch command which performs a staged commit
  8→//! with heat/pace context prefix. It accepts explicit file list and generates
  9→//! a JJ context-aware commit message.
 10→
 11→use clap::Args;
 12→use std::collections::HashSet;
 13→use std::process::Command;
 14→
 15→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX, JJRF_CORONET_PREFIX};
 16→use crate::jjrn_notch::{jjrn_format_notch_prefix, JJRN_COMMIT_PREFIX};
 17→
 18→/// Arguments for jjx_notch command
 19→#[derive(Args, Debug)]
 20→pub struct jjrnc_NotchArgs {
 21→    /// Identity: Coronet (5-char, pace-affiliated) or Firemark (2-char, heat-only)
 22→    pub identity: String,
 23→
 24→    /// Files to commit (required, at least one)
 25→    #[arg(required = true)]
 26→    pub files: Vec<String>,
 27→
 28→    /// Size limit in bytes (overrides default 50KB guard)
 29→    #[arg(long)]
 30→    pub size_limit: Option<u64>,
 31→
 32→    /// User-provided commit message intent (overrides haiku-generated message)
 33→    #[arg(long)]
 34→    pub intent: Option<String>,
 35→}
 36→
 37→/// Run the notch command
 38→///
 39→/// Stages specified files and commits with JJ-aware prefix.
 40→/// Supports both pace-affiliated (Coronet) and heat-only (Firemark) commits.
 41→pub fn jjrnc_run_notch(args: jjrnc_NotchArgs) -> i32 {
 42→    // Require non-empty files list
 43→    if args.files.is_empty() {
 44→        eprintln!("jjx_notch: error: at least one file required");
 45→        return 1;
 46→    }
 47→
 48→    // Check each file either exists on disk or is tracked by git (for deletions)
 49→    for file in &args.files {
 50→        let path_exists = std::path::Path::new(file).exists();
 51→
 52→        // If file doesn't exist on disk, check if it's tracked by git
 53→        if !path_exists {
 54→            let git_ls_output = match Command::new("git")
 55→                .args(["ls-files", "--error-unmatch", file])
 56→                .output()
 57→            {
 58→                Ok(o) => o,
 59→                Err(e) => {
 60→                    eprintln!("jjx_notch: error: failed to check git tracking: {}", e);
 61→                    return 1;
 62→                }
 63→            };
 64→
 65→            // If git ls-files fails, file is neither on disk nor tracked
 66→            if !git_ls_output.status.success() {
 67→                eprintln!("jjx_notch: error: file does not exist and is not tracked by git: {}", file);
 68→                return 1;
 69→            }
 70→        }
 71→    }
 72→
 73→    // Parse identity - support both Coronet (5 chars) and Firemark (2 chars)
 74→    let identity = args.identity.strip_prefix(JJRF_CORONET_PREFIX).or_else(|| args.identity.strip_prefix(JJRF_FIREMARK_PREFIX)).unwrap_or(&args.identity);
 75→
 76→    let message = if identity.len() == 5 {
 77→        // Coronet - pace-affiliated commit
 78→        let coronet = match Coronet::jjrf_parse(&args.identity) {
 79→            Ok(c) => c,
 80→            Err(e) => {
 81→                eprintln!("jjx_notch: error: {}", e);
 82→                return 1;
 83→            }
 84→        };
 85→        jjrn_format_notch_prefix(&coronet)
 86→    } else if identity.len() == 2 {
 87→        // Firemark - heat-only commit
 88→        let firemark = match Firemark::jjrf_parse(&args.identity) {
 89→            Ok(fm) => fm,
 90→            Err(e) => {
 91→                eprintln!("jjx_notch: error: {}", e);
 92→                return 1;
 93→            }
 94→        };
 95→        let hallmark = vvc::vvcc_get_hallmark();
 96→        let identity_str = format!("{}{}", JJRF_FIREMARK_PREFIX, firemark.jjrf_as_str());
 97→        vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity_str, "n", "", None)
 98→    } else {
 99→        eprintln!("jjx_notch: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
100→        return 1;
101→    };
102→
103→    // Warn about uncommitted changes outside the file list
104→    let output = match Command::new("git")
105→        .args(["status", "--porcelain"])
106→        .output()
107→    {
108→        Ok(o) => o,
109→        Err(e) => {
110→            eprintln!("jjx_notch: error: failed to run git status: {}", e);
111→            return 1;
112→        }
113→    };
114→
115→    if !output.status.success() {
116→        eprintln!("jjx_notch: error: git status failed");
117→        return 1;
118→    }
119→
120→    let status_output = String::from_utf8_lossy(&output.stdout);
121→    let files_set: HashSet<_> = args.files.iter().map(|s| s.as_str()).collect();
122→    let mut warnings = Vec::new();
123→
124→    for line in status_output.lines() {
125→        if line.len() < 4 {
126→            continue;
127→        }
128→        // Parse git status --porcelain format: "XY filename"
129→        let filepath = &line[3..];
130→        if !files_set.contains(filepath) {
131→            warnings.push(format!("  {}", line));
132→        }
133→    }
134→
135→    if !warnings.is_empty() {
136→        eprintln!("warning: uncommitted changes outside file list:");
137→        for warning in warnings {
138→            eprintln!("{}", warning);
139→        }
140→    }
141→
142→    // Stage only the specified files
143→    let mut git_add = Command::new("git");
144→    git_add.arg("add");
145→    for file in &args.files {
146→        git_add.arg(file);
147→    }
148→
149→    let add_output = match git_add.output() {
150→        Ok(o) => o,
151→        Err(e) => {
152→            eprintln!("jjx_notch: error: failed to run git add: {}", e);
153→            return 1;
154→        }
155→    };
156→
157→    if !add_output.status.success() {
158→        eprintln!("jjx_notch: error: git add failed");
159→        return 1;
160→    }
161→
162→    // Commit using vvc with the generated message prefix
163→    // If --intent provided, use it as the message; otherwise let haiku generate it
164→    let commit_args = if let Some(intent) = args.intent {
165→        vvc::vvcc_CommitArgs {
166→            prefix: None,
167→            message: Some(format!("{}{}", message, intent)),
168→            allow_empty: false,
169→            no_stage: true,  // We already staged above
170→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
171→            warn_limit: vvc::VVCG_WARN_LIMIT,
172→        }
173→    } else {
174→        vvc::vvcc_CommitArgs {
175→            prefix: Some(message),
176→            message: None,
177→            allow_empty: false,
178→            no_stage: true,  // We already staged above
179→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
180→            warn_limit: vvc::VVCG_WARN_LIMIT,
181→        }
182→    };
183→
184→    vvc::commit(&commit_args)
185→}
186→

